:root {
  --card-bg: #1a2744;
  --header-bg: #243057;
  --accent: #4f8ef7;
  --accent-light: #e8f0fe;
  --confirmed-bg: #1e4d2b;
  --confirmed-text: #4cde80;
  --text-primary: #ffffff;
  --text-secondary: #8fa3cc;
  --city-code-color: #ffffff;
  --time-color: #4f8ef7;
  --divider-color: #2e3f6a;
  --notch-color: #f5f5f5;
  --detail-label-color: #8fa3cc;
  --detail-value-color: #ffffff;
  --footer-bg: #243057;
  --price-color: #4f8ef7;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.booking-card {
  background-color: var(--card-bg);
  border-radius: 20px;
  width: 320px;
  overflow: hidden;
}

.card-header {
  background-color: var(--header-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 20px;
}

.airline-label {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.5px;
}

.flight-badge {
  background-color: var(--confirmed-bg);
  color: var(--confirmed-text);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
  letter-spacing: 0.3px;
}

.route-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 24px 20px 20px;
  gap: 8px;
}

.city-block {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 4px;
}

.city-block--right {
  align-items: flex-end;
}

.city-code {
  font-size: 30px;
  font-weight: 800;
  color: var(--city-code-color);
  line-height: 1;
}

.city-name {
  font-size: 11px;
  color: var(--text-secondary);
  font-weight: 400;
}

.time {
  font-size: 13px;
  font-weight: 600;
  color: var(--time-color);
  margin-top: 2px;
}

.route-line {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  flex: 1;
}

.plane-icon {
  font-size: 18px;
  color: var(--accent);
}

.dashed-line {
  width: 100%;
  height: 1px;
  border-top: 2px dashed var(--divider-color);
}

.duration {
  font-size: 11px;
  color: var(--text-secondary);
  font-weight: 500;
}

.divider {
  display: flex;
  align-items: center;
  margin: 0 0;
  position: relative;
}

.notch {
  width: 20px;
  height: 20px;
  background-color: var(--notch-color);
  border-radius: 50%;
  flex-shrink: 0;
}

.notch--left {
  margin-left: -10px;
}

.notch--right {
  margin-right: -10px;
}

.dashed-divider {
  flex: 1;
  border-top: 2px dashed var(--divider-color);
}

.details-row {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr 1fr;
  padding: 18px 20px;
  gap: 12px;
}

.detail-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.detail-label {
  font-size: 10px;
  color: var(--detail-label-color);
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.detail-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--detail-value-color);
}

.card-footer {
  background-color: var(--footer-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 20px;
}

.price-label {
  font-size: 13px;
  color: var(--text-secondary);
  font-weight: 500;
}

.price-value {
  font-size: 22px;
  font-weight: 800;
  color: var(--price-color);
}
